class GlobalREITSimulator:
    def calculate_property_value(self, noi: float, cap_rate: float) -> float:
        """Net İşletme Geliri üzerinden Mülk Değerleme."""
        if cap_rate <= 0: return float('inf')
        return noi / cap_rate
        
